------------------------------------------------------------------------------
-- Package Header
------------------------------------------------------------------------------
package psi_ms_daq_pkg is

  constant MaxStreams_c     : integer := 32;
  constant MaxWindows_c     : integer := 32;
  constant MaxStreamsBits_c : integer := log2ceil(MaxStreams_c);
