24		use work.psi_tb_activity_pkg.all;
25	
26	------------------------------------------------------------
27	-- Package Header
28	------------------------------------------------------------
29	package psi_ms_daq_input_tb_case_modes is
30		
31		procedure stream (
32			signal Str_Clk : in std_logic;
33			signal Str_Vld : inout std_logic;
34			signal Str_Rdy : in std_logic;
35			signal Str_Data : inout std_logic_vector;
36			signal Str_Trig : inout std_logic;
37			signal Str_Ts : inout std_logic_vector;
38			signal Clk : in std_logic;
39			signal Arm : inout std_logic;
40			signal IsArmed : in std_logic;
41			constant Generics_c : Generics_t);
42			
43		procedure daq (
44			signal Clk : in std_logic;
45			signal PostTrigSpls : inout std_logic_vector;
46			signal Mode : inout RecMode_t;
47			signal Daq_Vld : in std_logic;
48			signal Daq_Rdy : inout std_logic;
49			signal Daq_Data : in Input2Daq_Data_t(Data(IntDataWidth_g-1 downto 0), Bytes(log2ceil(IntDataWidth_g/8) downto 0));
50			signal Daq_Level : in std_logic_vector;
51			signal Daq_HasLast : in std_logic;
52			signal Ts_Vld : in std_logic;
53			signal Ts_Rdy : inout std_logic;
54			signal Ts_Data : in std_logic_vector;
55			constant Generics_c : Generics_t);
56			
57		shared variable TestCase : integer := -1;
58		shared variable StrDone  : boolean := false;
59			
60	end package;
61	
62	------------------------------------------------------------
63	-- Package Body
64	------------------------------------------------------------
65	package body psi_ms_daq_input_tb_case_modes is
66		procedure stream (
67			signal Str_Clk : in std_logic;
68			signal Str_Vld : inout std_logic;
69			signal Str_Rdy : in std_logic;
70			signal Str_Data : inout std_logic_vector;
71			signal Str_Trig : inout std_logic;
72			signal Str_Ts : inout std_logic_vector;
73			signal Clk : in std_logic;
74			signal Arm : inout std_logic;
75			signal IsArmed : in std_logic;
76			constant Generics_c : Generics_t) is
77		begin
78			
79			-- Trigger Mask Mode
80			while TestCase /= 0 loop
81				wait until rising_edge(Str_Clk);
82			end loop;
83			wait for 100 ns;
84			-- Recorded but trigger lost
85			ApplyStrData(5, 1, 1, Generics_c, Str_Clk, Str_Vld, Str_Rdy, Str_Data, Str_Trig, Str_Ts);
86			-- Received
87			PulseSig(Arm, Clk);
88			wait for 100 ns;
89			ApplyStrData(4, 0, 2, Generics_c, Str_Clk, Str_Vld, Str_Rdy, Str_Data, Str_Trig, Str_Ts, 5);
90			-- Lost
91			ApplyStrData(7, 3, 3, Generics_c, Str_Clk, Str_Vld, Str_Rdy, Str_Data, Str_Trig, Str_Ts);	
92			StrDone := true;
93			
94			-- Single Shot Mode
95			while TestCase /= 1 loop
96				wait until rising_edge(Str_Clk);
97			end loop;
98			wait for 100 ns;
99			-- Lost
100			ApplyStrData(5, 1, 1, Generics_c, Str_Clk, Str_Vld, Str_Rdy, Str_Data, Str_Trig, Str_Ts);
101			-- Received
102			PulseSig(Arm, Clk);
103			wait for 100 ns;
104			ApplyStrData(6, 2, 2, Generics_c, Str_Clk, Str_Vld, Str_Rdy, Str_Data, Str_Trig, Str_Ts, 5);
105			-- Lost
106			ApplyStrData(7, 3, 3, Generics_c, Str_Clk, Str_Vld, Str_Rdy, Str_Data, Str_Trig, Str_Ts, 5+6);
107			StrDone := true;
108	
109			-- Manual Mode
110			while TestCase /= 2 loop
111				wait until rising_edge(Str_Clk);
112			end loop;
113			wait for 100 ns;
114			-- Lost
115			ApplyStrData(5, 1, 1, Generics_c, Str_Clk, Str_Vld, Str_Rdy, Str_Data, Str_Trig, Str_Ts);
116			-- Received (partially)
117			Str_Ts <= std_logic_vector(to_unsigned(10, 64));
118			PulseSig(Arm, Clk);
119			wait for 100 ns;
120			Str_Ts <= std_logic_vector(to_unsigned(0, 64));
121			ApplyStrData(100, 80, 2, Generics_c, Str_Clk, Str_Vld, Str_Rdy, Str_Data, Str_Trig, Str_Ts, 5);
122			-- Lost
123			ApplyStrData(7, 3, 3, Generics_c, Str_Clk, Str_Vld, Str_Rdy, Str_Data, Str_Trig, Str_Ts, 5+6);			
124			StrDone := true;		
125			
126		end procedure;
127		
128		procedure daq (
129			signal Clk : in std_logic;
130			signal PostTrigSpls : inout std_logic_vector;
131			signal Mode : inout RecMode_t;
132			signal Daq_Vld : in std_logic;
133			signal Daq_Rdy : inout std_logic;
134			signal Daq_Data : in Input2Daq_Data_t(Data(IntDataWidth_g-1 downto 0), Bytes(log2ceil(IntDataWidth_g/8) downto 0));
135			signal Daq_Level : in std_logic_vector;
136			signal Daq_HasLast : in std_logic;
137			signal Ts_Vld : in std_logic;
138			signal Ts_Rdy : inout std_logic;
139			signal Ts_Data : in std_logic_vector;
140			constant Generics_c : Generics_t) is
141		begin
142			-- Config
143			PostTrigSpls <= std_logic_vector(to_unsigned(3, 32));
144			Daq_Rdy <= '0';
145			
146			-- Trigger Mask Mode
147			print(">> Trigger Mask Mode");	
148			StrDone := false;
149			Mode <= RecMode_TriggerMask_c;
150			TestCase := 0;
151			CheckAcqData (5+4, 2, Generics_c, FrameType_Trigger_c, Clk, Daq_Vld, Daq_Rdy, Daq_Data, Ts_Vld, Ts_Rdy, Ts_Data);
152			wait for 100 ns;
153			CheckAcqData (7, 3, Generics_c, FrameType_Timeout_c, Clk, Daq_Vld, Daq_Rdy, Daq_Data, Ts_Vld, Ts_Rdy, Ts_Data);
154			while not StrDone loop
155				wait until rising_edge(Clk);
